import { tags } from 'decantr/tags';
import { createSignal } from 'decantr/state';
import { css } from 'decantr/css';
import { Button, Badge, icon } from 'decantr/components';

code.example:
function ChatHeader({ title, model, onSearch, onExport, onSettings }) {
  const { div, h2, input, span } = tags;
  const [isEditing, setIsEditing] = createSignal(false);
  const [editTitle, setEditTitle] = createSignal(title);

  return div({ class: css('_flex _aic _jcsb _px6 _py3 _borderB _bgbg') },
    div({ class: css('_flex _aic _gap3') },
      isEditing() 
        ? input({
            class: css('carbon-input _heading4 _p1'),
            value: editTitle(),
            oninput: (e) => setEditTitle(e.target.value),
            onblur: () => setIsEditing(false),
            onkeydown: (e) => e.key === 'Enter' && setIsEditing(false)
          })
        : h2({ 
            class: css('_heading4 _cursor[pointer]'),
            onclick: () => setIsEditing(true)
          }, editTitle()),
      Badge({ variant: 'outline', size: 'sm' }, model || 'GPT-4')
    ),
    div({ class: css('_flex _aic _gap1') },
      Button({ variant: 'ghost', size: 'sm', onclick: onSearch }, icon('search')),
      Button({ variant: 'ghost', size: 'sm', onclick: onExport }, icon('download')),
      Button({ variant: 'ghost', size: 'sm', onclick: onSettings }, icon('settings'))
    )
  );
}

