code.example:
function CompactChatHeader({ title, onMenu }) {
  const { div, span } = tags;

  return div({ class: css('_flex _aic _jcsb _px4 _py2 _borderB _bgbg') },
    Button({ variant: 'ghost', size: 'sm', onclick: () => navigate('/chat') },
      icon('arrow-left')
    ),
    span({ class: css('_heading5 _truncate _flex1 _tc') }, title),
    Button({ variant: 'ghost', size: 'sm', onclick: onMenu },
      icon('more-vertical')
    )
  );
}

